import heapq

def _bellman_ford(num_vertices, edges):
    bf_edges = []
    for u, v, weight in edges:
        bf_edges.append((u, v, weight))

    s_node = num_vertices
    for i in range(num_vertices):
        bf_edges.append((s_node, i, 0))

    h = [float('inf')] * (num_vertices + 1)
    h[s_node] = 0

    for _ in range(num_vertices + 1):
        relaxed_in_iter = False
        for u, v, weight in bf_edges:
            if h[u] != float('inf') and h[u] + weight < h[v]:
                h[v] = h[u] + weight
                relaxed_in_iter = True
        if not relaxed_in_iter and _ < num_vertices:
            break

    for u, v, weight in bf_edges:
        if h[u] != float('inf') and h[u] + weight < h[v]:
            return None

    return h[:num_vertices]


def _dijkstra(graph_reweighted, start_node, num_vertices):
    distances = [float('inf')] * num_vertices
    distances[start_node] = 0
    priority_queue = [(0, start_node)]

    while priority_queue:
        current_dist, u = heapq.heappop(priority_queue)

        if current_dist > distances[u]:
            continue

        for v, weight in graph_reweighted.get(u, []):
            if distances[u] + weight < distances[v]:
                distances[v] = distances[u] + weight
                heapq.heappush(priority_queue, (distances[v], v))

    return distances


def johnson_algorithm(num_vertices, edges):
    h = _bellman_ford(num_vertices, edges)

    if h is None:
        return None

    graph_reweighted = {i: [] for i in range(num_vertices)}
    for u, v, weight in edges:
        reweighted_weight = weight + h[u] - h[v]
        graph_reweighted[u].append((v, reweighted_weight))

    all_pairs_distances = [[float('inf')] * num_vertices for _ in range(num_vertices)]

    for u in range(num_vertices):
        all_pairs_distances[u][u] = 0 

        distances_from_u_prime = _dijkstra(graph_reweighted, u, num_vertices)

        for v in range(num_vertices):
            if distances_from_u_prime[v] != float('inf'):
                all_pairs_distances[u][v] = distances_from_u_prime[v] - h[u] + h[v]

    return all_pairs_distances
